import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
    const gameRef = useRef(null);
    let player;

    useEffect(() => {
        const initializeGame = () => {
            const config = {
                type: Phaser.AUTO,
                width: 800,
                height: 600,
                scene: {
                    preload: preload,
                    create: create
                },
                physics: {
                    default: 'arcade',
                    arcade: {
                        gravity: { y: 0 },
                        debug: false
                    }
                }
            };

            gameRef.current = new Phaser.Game(config);
        };

        function preload() {
            this.load.image('player', 'assets/player.png');
        }

        function create() {
            player = this.physics.add.sprite(400, 300, 'player');
            player.setCollideWorldBounds(true);

            const cursors = this.input.keyboard.createCursorKeys();

            cursors.up.on('down', () => movePlayer('up'));
            cursors.down.on('down', () => movePlayer('down'));
            cursors.left.on('down', () => movePlayer('left'));
            cursors.right.on('down', () => movePlayer('right'));
        }

        function movePlayer(direction) {
            const speed = 200;

            switch(direction) {
                case 'up':
                    player.setVelocity(0, -speed);
                    break;
                case 'down':
                    player.setVelocity(0, speed);
                    break;
                case 'left':
                    player.setVelocity(-speed, 0);
                    break;
                case 'right':
                    player.setVelocity(speed, 0);
                    break;
            }
        }

        initializeGame();

        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
            }
        };
    }, []);

    return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
